const IndexPage = ({ location }) => {
  const sectionLinks = useMemo(
    () => navLinks.filter(({ url }) => ['/#about', '/#jobs', '/#projects', '/#contact'].includes(url)),
    [],
  );
  const [activeNavLink, setActiveNavLink] = useState('/#about');

  useEffect(() => {
    if (location.hash) {
      setActiveNavLink(`/${location.hash}`);
    }
  }, [location.hash]);

  useEffect(() => {
    if (typeof window === 'undefined') {
      return undefined;
    }

    const sections = sectionLinks
      .map(({ url }) => {
        const id = url.replace('/#', '');
        return {
          id,
          url,
          el: document.getElementById(id),
        };
      })
      .filter(item => item.el);

    if (sections.length === 0) {
      return undefined;
    }

    const observer = new IntersectionObserver(
      entries => {
        const visible = entries
          .filter(entry => entry.isIntersecting)
          .sort((a, b) => b.intersectionRatio - a.intersectionRatio);

        if (visible.length > 0) {
          const activeSection = sections.find(item => item.el === visible[0].target);
          if (activeSection) {
            setActiveNavLink(activeSection.url);
          }
        }
      },
      {
        rootMargin: '-30% 0px -55% 0px',
        threshold: [0.1, 0.25, 0.4, 0.6],
      },
    );

    sections.forEach(section => observer.observe(section.el));

    return () => {
      sections.forEach(section => observer.unobserve(section.el));
      observer.disconnect();
    };
  }, [sectionLinks]);

  return (
    <Layout location={location}>
      <StyledHomePage>
        <StyledHomeGrid>
          <StyledSidebar>
            <StyledIntro>
              <div className="eyebrow">Frontend Engineer</div>
              <h1>Thomas Doan.</h1>
              <div className="title">I build thoughtful web products.</div>
              <p className="summary">
                I care about accessible interfaces, clean systems, and the details that make products feel
                calm and trustworthy.
              </p>
            </StyledIntro>

            <StyledSectionNav aria-label="Section navigation">
              <ol>
                <li>
                  <a
                    href="/#about"
                    className={activeNavLink === '/#about' ? 'active' : ''}
                    aria-current={activeNavLink === '/#about' ? 'page' : undefined}>
                    About
                  </a>
                </li>
                <li>
                  <a
                    href="/#jobs"
                    className={activeNavLink === '/#jobs' ? 'active' : ''}
                    aria-current={activeNavLink === '/#jobs' ? 'page' : undefined}>
                    Experience
                  </a>
                </li>
                <li>
                  <a
                    href="/#projects"
                    className={activeNavLink === '/#projects' ? 'active' : ''}
                    aria-current={activeNavLink === '/#projects' ? 'page' : undefined}>
                    Projects
                  </a>
                </li>
                <li>
                  <a
                    href="/#contact"
                    className={activeNavLink === '/#contact' ? 'active' : ''}
                    aria-current={activeNavLink === '/#contact' ? 'page' : undefined}>
                    Contact
                  </a>
                </li>
              </ol>
            </StyledSectionNav>

            <StyledSidebarActions>
              <a href="/resume.pdf" target="_blank" rel="noopener noreferrer">
                Resume
              </a>
              <a href={`mailto:${email}`}>Email</a>
            </StyledSidebarActions>

            <StyledSocialRow aria-label="Social links">
              {socialMedia.map(({ url, name }) => (
                <li key={name}>
                  <a href={url} aria-label={name} target="_blank" rel="noopener noreferrer">
                    <Icon name={name} />
                  </a>
                </li>
              ))}
            </StyledSocialRow>
          </StyledSidebar>

          <StyledContent>
            <About />
            <Jobs />
            <Featured />
            <HomeBlogPreview />
            <Contact />

            <StyledFooterNote>
              Built with Gatsby, React, and Styled Components. Hosted with care and a lot of coffee.
            </StyledFooterNote>
          </StyledContent>
        </StyledHomeGrid>
      </StyledHomePage>
    </Layout>
  );
};

IndexPage.propTypes = {
  location: PropTypes.object.isRequired,
};

export default IndexPage;
